+fn load_settings_json_object(path: &Path) -> Result<Value> {
+    if !path.exists() {
+        return Ok(json!({}));
+    }
+
+    let content = std::fs::read_to_string(path)?;
+    if content.trim().is_empty() {
+        return Ok(json!({}));
+    }
+
+    let value: Value = serde_json::from_str(&content)?;
+    if value.is_object() {
+        Ok(value)
+    } else {
+        Ok(json!({}))
+    }
+}
